"""
memory_summarizer.py - 每日對話彙整與記憶提取

流程：
1. 掃描 ~/.linkpi/sessions/ 中過去 24 小時的 .jsonl 記錄。
2. 提取對話文本。
3. 使用 pi agent 分析並提取適合放入長期記憶的候選資訊。
4. 將結果推送到 LineBot，並儲存在 app.py 的 pending 狀態中以待確認。
"""

import os
import json
import logging
import pathlib
import requests
from datetime import datetime, timedelta
from pi_rpc import PiRpcClient

# Configure logging
logging.basicConfig(
    level=logging.INFO, 
    format="%(asctime)s [%(levelname)s] %(name)s: %(message)s"
)
logger = logging.getLogger("memory_summarizer")

# Configuration
LINKPI_DIR = pathlib.Path(os.environ.get("LINKPI_DIR", pathlib.Path.home() / ".linkpi"))
SESSIONS_DIR = LINKPI_DIR / "sessions"
LINEBOT_BASE_URL = os.getenv("LINEBOT_BASE_URL", "http://127.0.0.1:5000")
SCHEDULER_SECRET = os.getenv("SCHEDULER_SECRET", "")
USER_ID = os.getenv("WATER_REMINDER_USER_ID", "")
PI_CLI_PATH = os.getenv("PI_CLI_PATH", "pi")

def get_recent_sessions(hours=24):
    """Get all session .jsonl files modified in the last X hours."""
    recent_files = []
    cutoff = datetime.now() - timedelta(hours=hours)

    if not SESSIONS_DIR.exists():
        logger.warning(f"Sessions directory {SESSIONS_DIR} does not exist.")
        return []

    for provider_dir in SESSIONS_DIR.iterdir():
        if provider_dir.is_dir():
            for f in provider_dir.glob("*.jsonl"):
                mtime = datetime.fromtimestamp(f.stat().st_mtime)
                if mtime > cutoff:
                    recent_files.append(f)

    return recent_files

def extract_conversation(file_path):
    """Extract user and assistant text from a pi session .jsonl file."""
    conv = []
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            for line in f:
                try:
                    data = json.loads(line)
                    if data.get("type") == "message":
                        msg = data.get("message", {})
                        role = msg.get("role")
                        content = msg.get("content", [])

                        text = ""
                        if isinstance(content, list):
                            for item in content:
                                if isinstance(item, dict) and item.get("type") == "text":
                                    text += item.get("text", "")
                                elif isinstance(item, str):
                                    text += item
                        elif isinstance(content, str):
                            text = content

                        if role in ("user", "assistant") and text:
                            conv.append(f"{role}: {text}")
                except json.JSONDecodeError:
                    continue
    except Exception as e:
        logger.error(f"Error reading {file_path}: {e}")

    return "\n".join(conv)

def summarize_sessions(client: PiRpcClient, session_files):
    """Summarize each session and extract candidate memories.
    Returns a list of candidates: [{'session': ..., 'content': ...}]
    """
    candidates = []

    for f in session_files:
        conv = extract_conversation(f)
        if not conv:
            continue

        prompt = (
            "Below is a recording of a conversation between a user (Johnny) and an AI assistant (小白).\n"
            "Please analyze this conversation and extract any NEW information that should be stored in the assistant's long-term memory.\n"
            "This includes:\n"
            "- User preferences (e.g., 'I prefer low-carb dinners')\n"
            "- Personal facts (e.g., 'I live in Taichung')\n"
            "- Specific goals (e.g., 'I want to pass the TOEIC 500 test')\n"
            "- Important project decisions or architectural choices\n"
            "- Health-related constraints (e.g., 'Reduce salt for kidney health')\n\n"
            "Format the output as a bulleted list where each item is a distinct piece of information.\n"
            "If nothing new is found, simply say 'No new memory candidates'.\n\n"
            f"Conversation:\n---\n{conv}\n---\n\n"
            "Memory Candidates:"
        )

        try:
            summary = client.prompt(prompt)
            if "No new memory candidates" not in summary:
                # We store as a single block for now, but splitting by bullet would be better
                candidates.append({
                    "session": f.name,
                    "content": summary.strip()
                })
        except Exception as e:
            logger.error(f"Error summarizing {f.name}: {e}")

    return candidates

def upload_and_notify(candidates):
    """Upload candidates to app.py for pending confirmation and trigger push notification."""
    if not candidates:
        return False

    if not USER_ID:
        logger.error("USER_ID (WATER_REMINDER_USER_ID) is not set.")
        return False

    # 1. Upload to app.py /memory/pending
    url_pending = f"{LINEBOT_BASE_URL}/memory/pending"
    payload_pending = {
        "token": SCHEDULER_SECRET,
        "user_id": USER_ID,
        "candidates": candidates
    }
    try:
        resp = requests.post(url_pending, json=payload_pending, timeout=10)
        resp.raise_for_status()
    except Exception as e:
        logger.error(f"Failed to upload candidates to app.py: {e}")
        return False

    # 2. Push notification to user
    url_push = f"{LINEBOT_BASE_URL}/push"

    # Format the message for the user
    formatted_list = ""
    for i, c in enumerate(candidates, 1):
        formatted_list += f"【{i}】{c['content']}\n\n"

    full_text = (
        "🧠 **每日記憶彙整 (17:00)**\n\n"
        "小白彙整了昨天的對話，發現以下資訊建議加入長期記憶：\n\n"
        f"{formatted_list}"
        "--- \n"
        "強尼，請問哪些需要保留？\n"
        "請回覆編號（例如：1, 3）或「全部」或「略過」。"
    )

    payload_push = {
        "token": SCHEDULER_SECRET,
        "user_id": USER_ID,
        "text": full_text
    }
    try:
        resp = requests.post(url_push, json=payload_push, timeout=10)
        resp.raise_for_status()
        return True
    except Exception as e:
        logger.error(f"Failed to push notification to user: {e}")
        return False

def run_daily_memory_summary():
    """Main entry point for the daily memory summarizer."""
    logger.info("Starting daily memory summarization...")

    session_files = get_recent_sessions(24)
    if not session_files:
        logger.info("No recent sessions found. Nothing to summarize.")
        return

    logger.info(f"Found {len(session_files)} recent sessions.")

    try:
        client = PiRpcClient(
            base_cmd=PI_CLI_PATH.split(),
            env=os.environ.copy(),
        )
    except Exception as e:
        logger.error(f"Failed to initialize PiRpcClient: {e}")
        return

    try:
        candidates = summarize_sessions(client, session_files)
        if candidates:
            if upload_and_notify(candidates):
                logger.info("Memory summary processed and notification sent.")
            else:
                logger.error("Failed to notify user about memory candidates.")
        else:
            logger.info("No memory candidates extracted from recent sessions.")
    finally:
        client.close()

if __name__ == "__main__":
    run_daily_memory_summary()

